Setup
Create an OllamaClient with a tool-capable model and build a few demo tools from an in-process MCPClient via as_tools(). The tools are passed to each Agent via tools=; the same model_client and demo_tools are reused across all sections.

import datetime
from fastmcp import FastMCP

from aimu.models import OllamaClient
from aimu.tools import MCPClient

mcp = FastMCP("Demo Tools")


@mcp.tool()
def get_current_date_and_time() -&gt; str:
    """Returns the current date and time."""
    return str(datetime.datetime.now())


@mcp.tool()
def get_weather(location: str) -&gt; str:
    """Returns the current weather for a given location."""
    # Stubbed for demo purposes
    return f"Sunny, 22Â°C in {location}"


@mcp.tool()
def calculate(expression: str) -&gt; str:
    """Evaluates a simple arithmetic expression and returns the result."""
    try:
        return str(eval(expression, {"__builtins__": {}}))
    except Exception as e:
        return f"Error: {e}"


model_client = OllamaClient(OllamaClient.MODELS.QWEN_3_5_9B)
# MCPClient.as_tools() turns the server's tools into @tool-style callables. Tools now live
# on the Agent (pass them via tools=), not on the client; keep the MCPClient reference alive.
mcp_client = MCPClient(server=mcp)
demo_tools = mcp_client.as_tools()

print("Model:", model_client.model.value)
print("Tools:", [fn.__name__ for fn in demo_tools])

Setup
Create a shared OllamaClient with a tool-capable model and build a few demo tools from an in-process MCPClient via as_tools(). The tools are passed to the agents that need them via tools=; the same model_client and demo_tools are reused across all sections.

import datetime
from fastmcp import FastMCP

from aimu.models import OllamaClient
from aimu.models import StreamingContentType
from aimu.tools import MCPClient

mcp = FastMCP("Demo Tools")


@mcp.tool()
def get_current_date_and_time() -&gt; str:
    """Returns the current date and time."""
    return str(datetime.datetime.now())


@mcp.tool()
def get_weather(location: str) -&gt; str:
    """Returns the current weather for a given location."""
    return f"Sunny, 22°C in {location}"  # stubbed


@mcp.tool()
def calculate(expression: str) -&gt; str:
    """Evaluates a simple arithmetic expression and returns the result."""
    try:
        return str(eval(expression, {"__builtins__": {}}))
    except Exception as e:
        return f"Error: {e}"


model_client = OllamaClient(OllamaClient.MODELS.QWEN_3_5_9B)
# Build the MCP server's tools as @tool-style callables via as_tools(); keep the client alive.
# Tools live on each Agent now (pass them via tools=), not on the model client.
mcp_client = MCPClient(server=mcp)
demo_tools = mcp_client.as_tools()

print("Model:", model_client.model.value)
print("Tools:", [fn.__name__ for fn in demo_tools])
